// ============================================================
// Seeding function
// ============================================================
async function withRetry<T>(fn: () => Promise<T>, retries = 5, delay = 4000): Promise<T> {
  for (let i = 0; i < retries; i++) {
    try { return await fn(); } catch (e: any) {
      if (i < retries - 1 && (e?.message?.includes("Can't reach database") || e?.message?.includes("connect"))) {
        console.log(`  ⏳ DB retry ${i+2}/${retries}...`);
        await new Promise(r => setTimeout(r, delay));
      } else throw e;
    }
  }
  throw new Error("Max retries");
}

async function seed(name: string, questions: Q[]) {
  const subject = await withRetry(() => prisma.subject.findFirst({ where: { name, level: "SHS" } }));
  if (!subject) { console.log(`  ${name} not found — skipping`); return; }

  const batchSize = 50;
  let totalCreated = 0;
  for (let i = 0; i < questions.length; i += batchSize) {
    const batch = questions.slice(i, i + batchSize);
    try {
      const result = await withRetry(() =>
        prisma.question.createMany({
          data: batch.map(q => ({
            level: "SHS", examType: "WASSCE" as any, subjectId: subject.id,
            topic: q.topic, year: q.year, questionText: q.questionText,
            optionA: q.optionA, optionB: q.optionB, optionC: q.optionC, optionD: q.optionD,
            correctOption: q.correctOption, explanation: q.explanation,
            difficulty: q.difficulty as any,
          })),
          skipDuplicates: true,
        })
      );
      totalCreated += result.count;
      console.log(`  ${name}: batch ${Math.floor(i/batchSize)+1} - ${result.count} created`);
    } catch (err: any) {
      console.log(`  ${name}: batch error - ${err.message.slice(0,80)}`);
    }
  }
  console.log(`  ${name}: ${totalCreated}/${questions.length} total created`);
}

async function warmUp() {
  for (let i = 0; i < 15; i++) {
    try {
      await prisma.$queryRaw`SELECT 1`;
      console.log("  ✓ DB connection established");
      return;
    } catch (e) {
      console.log(`  Warming up DB... attempt ${i+1}/15`);
      await new Promise(r => setTimeout(r, 5000));
    }
  }
  throw new Error("Could not connect to database after 15 attempts");
}

async function main() {
  console.log("=== Seeding SHS Core Subjects (Direct) ===");
  await warmUp();
  console.log(`  Core Mathematics: ${coreMathQ.length} questions`);
  console.log(`  Elective Mathematics: ${eMathQ.length} questions`);
  console.log(`  English Language: ${englishQ.length} questions`);
  console.log(`  Social Studies: ${socStudQ.length} questions`);
  console.log(`  Integrated Science: ${intSciQ.length} questions`);
  console.log(`  TOTAL: ${coreMathQ.length + eMathQ.length + englishQ.length + socStudQ.length + intSciQ.length}`);
  console.log("");

  await seed("Core Mathematics", coreMathQ);
  await seed("Elective Mathematics", eMathQ);
  await seed("English Language", englishQ);
  await seed("Social Studies", socStudQ);
  await seed("Integrated Science", intSciQ);

  console.log("\n=== Seeding Complete ===");
}

main().catch(console.error).finally(() => prisma.$disconnect());
